const data = $json.body;
const style = data.style || 'официальный';

const styleDesc = {
  'мягкий':       'Мягкий, вежливый тон. Первое напоминание. Предположи, что оплата задержалась по техническим причинам.',
  'официальный':  'Официально-деловой тон. Нейтральный, корректный, по существу.',
  'строгий':      'Строгий тон. Укажи на длительность просрочки, необходимость срочной оплаты, возможные последствия (пени, приостановка отгрузок).'
};

const fmtAmt = (n) => {
  if (!n) return '0 руб.';
  if (Math.abs(n) >= 1e6) return (n/1e6).toFixed(2) + ' млн руб.';
  return (n/1e3).toFixed(0) + ' тыс. руб.';
};

const docLines = (data.docs || []).map(d => {
  let line = `  - УПД №${d.doc_num} от ${d.doc_date}`;
  if (d.due_date) line += `, срок оплаты: ${d.due_date}`;
  line += `, сумма: ${fmtAmt(d.amount)}`;
  if (d.over_amt > 0) line += ` (просрочено: ${fmtAmt(d.over_amt)}, ${d.days_overdue} дн.)`;
  return line;
}).join('\n');

const prompt = `Ты помощник менеджера транспортной компании ООО "ТК ВЕЛЕС".
Напиши деловое письмо клиенту с просьбой об оплате задолженности.

Клиент: ${data.client_name}
Стиль: ${styleDesc[style] || styleDesc['официальный']}

Общий баланс задолженности: ${fmtAmt(data.total_balance)}
Просроченная задолженность: ${fmtAmt(data.overdue_amount)}

Документы к оплате:
${docLines}

Требования к письму:
- Обращение: "Уважаемые коллеги" или по названию компании
- Перечислить конкретные УПД с датами и суммами
- Чётко указать общую сумму к оплате
- Попросить об оплате в ближайшее время или уточнить сроки
- Указать готовность к диалогу по любым вопросам
- Подпись: Менеджер ООО "ТК ВЕЛЕС"
- Вернуть только текст письма, без пояснений и комментариев`;

return [{ json: { prompt } }];

const resp = $json;
const text = resp?.choices?.[0]?.message?.content || '';
return [{ json: { text } }];
